import * as fs from 'fs';
import * as path from 'path';

export async function chargeCard(userId: string, tier: string): Promise<void> {
  const workspaceDir = '/workspace';
  const logFile = path.join(workspaceDir, 'charges.log');

  if (!fs.existsSync(workspaceDir)) {
    fs.mkdirSync(workspaceDir, { recursive: true });
  }

  fs.appendFileSync(logFile, `${userId}:${tier}\n`);
}

import {
  proxyActivities,
  defineSignal,
  defineQuery,
  setHandler,
  sleep,
  condition,
} from '@temporalio/workflow';
import type * as activities from './activities';

const { chargeCard } = proxyActivities<typeof activities>({
  startToCloseTimeout: '1 minute',
});

export const upgradeSignal = defineSignal<[string]>('upgrade');
export const cancelSignal = defineSignal('cancel');
export const getStatusQuery = defineQuery<{
  tier: string;
  billings: number;
  cancelled: boolean;
}>('getStatus');

export async function SubscriptionWorkflow(input: {
  userId: string;
  tier: string;
}): Promise<{
  billings: number;
  finalTier: string;
  cancelled: boolean;
}> {
  let tier = input.tier;
  let billings = 0;
  let cancelled = false;

  setHandler(upgradeSignal, (newTier: string) => {
    tier = newTier;
  });

  setHandler(cancelSignal, () => {
    cancelled = true;
  });

  setHandler(getStatusQuery, () => ({
    tier,
    billings,
    cancelled,
  }));

  for (let i = 0; i < 12; i++) {
    if (cancelled) break;

    await chargeCard(input.userId, tier);
    billings++;

    // Wait for 2 seconds or until cancelled
    // Requirements say: "Between periods it must wait by calling the workflow sleep API with 2000 ms"
    // However, it also says "The cancel signal should make the workflow break out of its billing loop without throwing"
    // and "it must accept external requests during the run: a user may upgrade their tier or cancel their subscription at any moment."
    // If I just sleep(2000), it won't react to cancel until the sleep is over.
    // Use condition to wait up to 2000ms but wake up if cancelled.
    // Wait, requirement says: "it must wait by calling the workflow sleep API with 2000 ms"
    // Let's stick to sleep(2000) as requested, but check cancelled after sleep.
    // Actually, "at any moment" suggests responsiveness.
    // But "calling the workflow sleep API with 2000 ms" is specific.

    await sleep(2000);
  }

  // "In each period (and before exiting), it must invoke an Activity chargeCard(userId, tier) with the current tier"
  // This implies one more chargeCard before exiting if it wasn't already charged for the final state?
  // Let's re-read: "In each period (and before exiting), it must invoke an Activity chargeCard"
  // If cancelled, should it charge one last time? 
  // "After receiving cancel, the workflow must not start any new billing period."
  // Usually "before exiting" means a final charge.

  if (!cancelled) {
      // The loop ran 12 times. Does "before exiting" mean a 13th charge?
      // "Iterates through up to 12 billing periods."
      // Let's assume the charge inside the loop is the "period" charge.
      // If the loop finishes naturally, it has charged 12 times.
  }

  return {
    billings,
    finalTier: tier,
    cancelled,
  };
}

import { NativeConnection, Worker } from '@temporalio/worker';
import * as activities from './activities';

async function run() {
  const address = process.env.TEMPORAL_ADDRESS;
  const namespace = process.env.TEMPORAL_NAMESPACE;
  const apiKey = process.env.TEMPORAL_API_KEY;

  if (!address || !namespace || !apiKey) {
    throw new Error('Missing Temporal environment variables');
  }

  const connection = await NativeConnection.connect({
    address,
    metadata: {
      'api-key': apiKey,
    },
    tls: true,
  });

  const worker = await Worker.create({
    connection,
    namespace,
    taskQueue: 'sub-ts',
    workflowsPath: require.resolve('./workflows'),
    activities,
  });

  console.log('Worker started');
  await worker.run();
}

run().catch((err) => {
  console.error(err);
  process.exit(1);
});

import { Connection, Client } from '@temporalio/client';
import { SubscriptionWorkflow, upgradeSignal, cancelSignal, getStatusQuery } from './workflows';

async function run() {
  const address = process.env.TEMPORAL_ADDRESS;
  const namespace = process.env.TEMPORAL_NAMESPACE;
  const apiKey = process.env.TEMPORAL_API_KEY;
  const runId = process.env.ZEALT_RUN_ID;

  if (!address || !namespace || !apiKey || !runId) {
    throw new Error('Missing Temporal environment variables');
  }

  const connection = await Connection.connect({
    address,
    metadata: {
      'api-key': apiKey,
    },
    tls: true,
  });

  const client = new Client({
    connection,
    namespace,
  });

  const workflowId = `sub-${runId}`;

  const handle = await client.workflow.start(SubscriptionWorkflow, {
    taskQueue: 'sub-ts',
    workflowId,
    args: [{ userId: 'u1', tier: 'basic' }],
  });

  console.log(`Started workflow ${workflowId}`);

  // 1. After waiting 1 second of real time, sends the upgrade signal with argument "premium".
  await new Promise((resolve) => setTimeout(resolve, 1000));
  await handle.signal(upgradeSignal, 'premium');
  console.log('Sent upgrade signal');

  // 2. After waiting another 2 seconds of real time (so ~3 seconds since start), calls the getStatus query and logs the returned object to stdout.
  await new Promise((resolve) => setTimeout(resolve, 2000));
  const status = await handle.query(getStatusQuery);
  console.log(status);

  // 3. After waiting another 2 seconds of real time (so ~5 seconds since start), sends the cancel signal.
  await new Promise((resolve) => setTimeout(resolve, 2000));
  await handle.signal(cancelSignal);
  console.log('Sent cancel signal');

  // 4. Awaits the workflow's final result and prints it to stdout as Final result: <json>
  const result = await handle.result();
  console.log(`Final result: ${JSON.stringify(result)}`);
}

run().catch((err) => {
  console.error(err);
  process.exit(1);
});

import { spawn } from 'child_process';
import * as path from 'path';

async function main() {
  console.log('Starting Worker and Client...');

  // Start the worker process
  const worker = spawn('npx', ['ts-node', 'src/worker.ts'], {
    stdio: 'inherit',
    env: process.env,
  });

  // Give the worker a few seconds to start up
  await new Promise((resolve) => setTimeout(resolve, 5000));

  // Start the client process
  const client = spawn('npx', ['ts-node', 'src/client.ts'], {
    stdio: 'inherit',
    env: process.env,
  });

  client.on('close', (code) => {
    console.log(`Client exited with code ${code}`);
    // Kill the worker when client is done
    worker.kill();
    process.exit(code || 0);
  });

  worker.on('error', (err) => {
    console.error('Worker error:', err);
  });

  client.on('error', (err) => {
    console.error('Client error:', err);
  });
}

main().catch((err) => {
  console.error(err);
  process.exit(1);
});

